cd /workspace/YatCC && python3 << 'PYEOF'
# Restore original ConstantFolding.cpp from git, then create new passes
import subprocess
subprocess.run(['git', 'checkout', '--', 'task/4/ConstantFolding.cpp'], 
               capture_output=True, cwd='/workspace/YatCC')

# Check if restored
with open('task/4/ConstantFolding.cpp') as f:
    first = f.readline()
    print(f'First line: {first.strip()}')

# Create AlgebraicSimplify.hpp
open('task/4/AlgebraicSimplify.hpp', 'w').write('''#pragma once

#include <llvm/IR/PassManager.h>
#include <llvm/IR/IRBuilder>

class AlgebraicSimplify : public llvm::PassInfoMixin<AlgebraicSimplify>
{
public:
  llvm::PreservedAnalyses run(llvm::Module& mod,
                              llvm::ModuleAnalysisManager& mam);
};
''')

# Create AlgebraicSimplify.cpp  
open('task/4/AlgebraicSimplify.cpp', 'w').write('''#include "AlgebraicSimplify.hpp"
#include <llvm/IR/Instructions.h>
#include <llvm/IR/Constants.h>

using namespace llvm;

PreservedAnalyses AlgebraicSimplify::run(Module& mod, ModulePassManager <PASimplify>> module)
{
  for (Function& F : mod) {
    for (BasicBlock& BB : F) {
      SmallVector<Instruction*, 8> toErase;
      for (Instruction& I : BB) {
        if (auto* BO = dyn_cast<BinaryOperator>(&I)) {
          Value* L = BO->getOperand(0);
          Value* R = BO->getOperand(1);
          auto* LC = dyn_cast<ConstantInt>(L);
          auto* RC = dyn_cast<ConstantInt>(R);

          // X + 0 = X, X - 0 = X
          if (BO->getOpcode() == Instruction::Add && RC && RC->isZero()) {
            BO->replaceAllUsesWith(L); toErase.push_back(BO);
          }
          else if (BO->getOpcode() == Instruction::Sub && RC && RC->isZero()) {
            BO->replaceAllUsesWith(L); toErase.push_back(BO);
          }
          else if (BO->getOpcode() == Instruction::Sub && L == R) {
            BO->replaceAllUsesWith(ConstantInt::get(BO->getType(), 0)); toErase.push_back(BO);
          }
          // X * 1 = X, X * 0 = 0
          else if (BO->getOpcode() == Instruction::Mul && RC && RC->isOne()) {
            BO->replaceAllUsesWith(L); toErase.push_back(BO);
          }
          else if (BO->getOpcode() == Instruction::Mul && RC && RC->isZero()) {
            BO->replaceAllUsesWith(ConstantInt::get(BO->getType(), 0)); toErase.push_back(BO);
          }
          // X / 1 = X
          else if (BO->getOpcode() == Instruction::SDiv && RC && RC->isOne()) {
            BO->replaceAllUsesWith(L); toErase.push_back(BO);
          }
          // X ^ X = 0
          else if (BO->getOpcode() == Instruction::Xor && L == R) {
            BO->replaceAllUsesWith(ConstantInt::get(BO->getType(), 0)); toErase.push_back(BO);
          }
          // X & 0 = 0
          else if (BO->getOpcode() == Instruction::And && ((LC && LC->isZero()) || (RC && RC->isZero()))) {
            BO->replaceAllUsesWith(ConstantInt::get(BO->getType(), 0)); toErase.push_back(BO);
          }
          // X & -1 = X
          else if (BO->getOpcode() == Instruction::And && RC && RC->isMinusOne()) {
            BO->replaceAllUsesWith(L); toErase.push_back(BO);
          }
          // X | 0 = X, X | -1 = -1
          else if (BO->getOpcode() == Instruction::Or && RC && RC->isZero()) {
            BO->replaceAllUsesWith(L); toErase.push_back(BO);
          }
          else if (BO->getOpcode() == Instruction::Or && RC && RC->isMinusOne()) {
            BO->replaceAllUsesWith(R); toErase.push_back(BO);
          }
          // X << 0 = X, X >> 0 = X
          else if ((BO->getOpcode() == Instruction::Shl || 
                    BO->getOpcode() == Instruction::AShr ||
                    BO->getOpcode() == Instruction::LShr) && RC && RC->isZero()) {
            BO->replaceAllUsesWith(L); toErase.push_back(BO);
          }
        }
      }
      for (auto* I : toErase) I->eraseFromParent();
    }
  }
  return PreservedAnalyses::all();
}
''')

